    <p style="margin:0 0 24px;color:rgba(255,255,255,.78);line-height:1.9;">
      <?= h($agent['person_name'] ?? '') ?>（<?= h($agent['agent_name'] ?? '') ?>）が担当します。<br>
      ご質問や無料体験のご相談は、LINEまたはフォームからお送りください。
    </p>

    <?php if ($showLinBtn): ?>
      <p style="margin:0 0 <?= $showForm ? '22px' : '0' ?>;">
        <a href="/line_click.php?agent_id=<?= (int)$agent['id'] ?>" target="_blank" rel="noopener" style="display:flex;align-items:center;justify-content:center;min-height:54px;padding:14px 20px;background:#06c755;color:#fff;border-radius:10px;text-decoration:none;font-weight:800;">
          LINEで相談する
        </a>
      </p>
    <?php endif; ?>

    <?php if ($showForm): ?>
      <form id="__contactForm" novalidate style="display:grid;gap:14px;">
        <input type="hidden" name="agent_id" value="<?= (int)$agent['id'] ?>">
        <input type="hidden" name="template_id" value="<?= (int)($agent['default_template_id'] ?? 0) ?>">
        <input type="hidden" name="csrf_token" value="<?= h($csrfToken) ?>">
        <input type="text" name="name" required placeholder="お名前" style="width:100%;padding:14px 16px;border:1px solid rgba(255,255,255,.24);border-radius:10px;background:rgba(255,255,255,.08);color:#fff;font-size:16px;">
        <input type="email" name="email" required placeholder="メールアドレス" style="width:100%;padding:14px 16px;border:1px solid rgba(255,255,255,.24);border-radius:10px;background:rgba(255,255,255,.08);color:#fff;font-size:16px;">
        <input type="tel" name="phone" placeholder="電話番号" style="width:100%;padding:14px 16px;border:1px solid rgba(255,255,255,.24);border-radius:10px;background:rgba(255,255,255,.08);color:#fff;font-size:16px;">
        <textarea name="message" required placeholder="お問い合わせ内容" style="width:100%;min-height:130px;padding:14px 16px;border:1px solid rgba(255,255,255,.24);border-radius:10px;background:rgba(255,255,255,.08);color:#fff;font-size:16px;"></textarea>
        <div id="__formMsg" style="display:none;padding:12px 14px;border-radius:10px;font-size:14px;"></div>
        <button id="__submitBtn" type="submit" style="min-height:56px;border:0;border-radius:10px;background:#d8b84a;color:#111;font-weight:900;font-size:16px;cursor:pointer;">送信する</button>
      </form>
      <script>
      (function(){
        var form = document.getElementById('__contactForm');
        if (!form) return;
        form.addEventListener('submit', async function(e) {
          e.preventDefault();
          var btn = document.getElementById('__submitBtn');
          var msg = document.getElementById('__formMsg');
          var original = btn.textContent;
          btn.disabled = true;
          btn.textContent = '送信中...';
          msg.style.display = 'none';
          var data = {};
          new FormData(form).forEach(function(v,k){ data[k] = v; });
          try {
            var res = await fetch('/contact.php', { method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(data) });
            var json = await res.json();
            msg.style.display = 'block';
            if (json.success) {
              msg.style.background = 'rgba(6,199,85,.16)';
              msg.style.border = '1px solid rgba(6,199,85,.45)';
              msg.style.color = '#8ff0b1';
              msg.textContent = json.message || '送信しました。';
              form.reset();
            } else {
              msg.style.background = 'rgba(180,40,40,.18)';
              msg.style.border = '1px solid rgba(220,80,80,.45)';
              msg.style.color = '#ffb2b2';
              msg.textContent = (json.errors || []).join(' / ') || json.message || '送信に失敗しました。';
            }
          } catch (err) {
            msg.style.display = 'block';
            msg.style.background = 'rgba(180,40,40,.18)';
            msg.style.border = '1px solid rgba(220,80,80,.45)';
            msg.style.color = '#ffb2b2';
            msg.textContent = '通信エラーが発生しました。時間をおいて再度お試しください。';
          } finally {
            btn.disabled = false;
            btn.textContent = original;
            msg.scrollIntoView({behavior:'smooth', block:'nearest'});
          }
        });
      })();
      </script>
    <?php endif; ?>
  </div>
</section>
</body>
</html>